package be.schaubroeck.lpb.rkm.rekenmotor.bruto;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.LoonElementVerwerker;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.GewoonLoon;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.GewoonLoonFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.WerknemersKengetalFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.MoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PrestatieSamenvatting;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Rszppo;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.rsz.Kengetal;
import lombok.AllArgsConstructor;

import java.math.BigDecimal;
import java.util.Collection;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBrutoKey.BASIS_BEDRAG_KEY;

@AllArgsConstructor
public class PrestatiesEuropeseVakantie {

    private static final int SCALE = 2;

    private final ConstantManager constantManager;
    private final LoonElementVerwerker loonElementVerwerker;

    public void verwerk(
            LoonElementManager manager, LoonCodeManager loonCodeManager, RekenTijd rekenTijd,
            PrestatieSamenvatting samenvatting, BigDecimal prestatieNoemer, Opper opper, MoneyMap<AardKodeExtensie> carryoverMap) {
        Collection<LoonElement> loonElementen = manager.getOpperElementen(opper);
        Money basisBedragEv = Money.ZERO;
        for (LoonElement element : loonElementen) {
            AardKodeExtensie aardKodeExtensie = element.getAardKodeExtensie();
            if (!aardKodeExtensie.isForfaitair()) {
                basisBedragEv = basisBedragEv.add(element.getPropertyMoney(BASIS_BEDRAG_KEY));
            }
        }
        if (samenvatting.getTellerEuropeseVakantie().signum() > 0) {
            Money bedrag = berekenBedragVoorTeller(basisBedragEv, samenvatting.getTellerEuropeseVakantie(), prestatieNoemer);
            GewoonLoon gewoonLoon = GewoonLoonFactory.getGewoonLoon(loonCodeManager, rekenTijd);

            Money bedragEv = bedrag;
            Money bedragEvDd4w = Money.ZERO;
            Rszppo rsppo = opper.getRszppo();
            Kengetal kengetal = WerknemersKengetalFactory.getKengetal(rekenTijd, rsppo.getWerknemersKengetal());
            boolean isGescoOfArt60p7 = kengetal.isGesco() || kengetal.isArtikel60p7();
            if (!isGescoOfArt60p7) {
                BigDecimal percentageEv = constantManager.getActualConstant(Konstanten.KST_EUROPESE_VAKANTIE, rekenTijd).getProcentFactor();
                bedragEv = bedrag.multiply(percentageEv);
                BigDecimal percentageEvDd4w = constantManager.getActualConstant(Konstanten.KST_EUROPESE_VAKANTIE_DD4W, rekenTijd).getProcentFactor();
                bedragEvDd4w = bedrag.multiply(percentageEvDd4w);
            }
            Money bassiEv = bedragEv;
            Money bassiEvDd4w = bedragEvDd4w;
            if (BrutoTools.heeftFactorBassi_1_25(opper, rekenTijd)) {
                bassiEv = bassiEv.multiply(BrutoTools.FACTOR_BASSI_1_25).round(SCALE);
                bassiEvDd4w = bassiEvDd4w.multiply(BrutoTools.FACTOR_BASSI_1_25).round(SCALE);
            }

            AardKodeExtensie looncodeEv = gewoonLoon.createAanvullendEuropeesVakantieGeld();
            loonElementVerwerker.verwerkTotLoonElement(opper, manager, looncodeEv, bedragEv, bassiEv, rekenTijd, carryoverMap);

            if (!isGescoOfArt60p7) {
                AardKodeExtensie looncodeEvDd4w = gewoonLoon.createAanvullendEuropeesVakantieGeldDd4w();
                loonElementVerwerker.verwerkTotLoonElement(opper, manager, looncodeEvDd4w, bedragEvDd4w, bassiEvDd4w, rekenTijd, carryoverMap);
            }
        }
    }

    private Money berekenBedragVoorTeller(Money bedrag, BigDecimal teller, BigDecimal noemer) {
        return bedrag.multiply(teller).divide(noemer);
    }

}
